const widget = space.chat.transient.get("snake-game");
if (!widget) throw new Error('snake-game transient missing');

const text = widget.text ?? widget.source ?? widget.content ?? widget.code ?? widget;
const source = typeof text === 'string' ? text : JSON.stringify(text);

const edits = [];

function replaceFirst(match, replacement) {
  const idx = source.indexOf(match);
  if (idx === -1) throw new Error(`Could not find: ${match}`);
  edits.push({ start: idx, end: idx + match.length, replace: replacement });
}

let next = source;

const patches = [
  {
    find: /const\s+CELL_SIZE\s*=\s*\d+\s*;?/,
    replace: m => `${m}\nconst ANIM_DURATION = 120;`
  },
  {
    find: /function\s+renderSnake[\s\S]*?}\n/,
    replace: m => m
  }
];

function applyRegexReplacement(pattern, replacement) {
  const match = next.match(pattern);
  if (!match) throw new Error(`Pattern not found: ${pattern}`);
  next = next.replace(pattern, replacement);
}

if (/function\s+drawSnake/.test(next) && /function\s+moveSnake/.test(next)) {
  next = next.replace(
    /function\s+drawSnake\s*\(([\s\S]*?)\)\s*\{[\s\S]*?\n\}/,
    (m) => m.replace(/ctx\.fillRect\(([^)]*)\);/g, 'ctx.save(); ctx.translate(drawX, drawY); ctx.fillRect(0, 0, CELL_SIZE, CELL_SIZE); ctx.restore();')
  );
}

if (/let\s+snake\s*=/.test(next) && !/snakeSegments/.test(next)) {
  next = next.replace(
    /let\s+snake\s*=\s*([^;]+);/,
    (m, init) => `${m}\nlet snakeSegments = ${init};\nlet lastMoveTime = performance.now();`
  );
}

next = next
  .replace(/snake\.unshift\(([^)]+)\);\s*snake\.pop\(\);/g, `snake.unshift($1);\n  snake.pop();\n  lastMoveTime = performance.now();`)
  .replace(/ctx\.fillRect\(\s*([a-zA-Z_$][\w$]*)\s*\*\s*CELL_SIZE\s*,\s*([a-zA-Z_$][\w$]*)\s*\*\s*CELL_SIZE\s*,\s*CELL_SIZE\s*,\s*CELL_SIZE\s*\);/g,
    'const progress = Math.min(1, (performance.now() - lastMoveTime) / ANIM_DURATION);\n  const drawX = $1 * CELL_SIZE;\n  const drawY = $2 * CELL_SIZE;\n  ctx.fillRect(drawX, drawY, CELL_SIZE, CELL_SIZE);'
  );

next = next.replace(
  /requestAnimationFrame\(\s*loop\s*\);/,
  `requestAnimationFrame(loop);`
);

return await space.current.patchWidget("snake-game", {
  edits: [{ start: 0, end: source.length, replace: next }]
});

