const src = typeof widget === "string" ? widget : (widget?.content ?? widget?.text ?? JSON.stringify(widget));
const patches = [];
const greenish = [
  { find: /background\s*:\s*[^;]+;/g, replace: "background: #c7d8a0;" },
  { find: /background-color\s*:\s*[^;]+;/g, replace: "background-color: #c7d8a0;" },
  { find: /color\s*:\s*[^;]+;/g, replace: "color: #243b1e;" },
  { find: /#([0-9a-fA-F]{3,6})/g, replace: (m) => m }
];
let edited = src;
for (const p of greenish) edited = edited.replace(p.find, p.replace);
if (edited === src) {
  edited = src + "\n\n/* Nokia green display */\nbody, .snake-game, canvas {\n  background: #c7d8a0 !important;\n  color: #243b1e !important;\n  filter: contrast(1.05) saturate(0.75);\n}\n";
}
return await space.current.patchWidget("snake-game", {
  edits: [{ type: "replace", text: edited }]
});

